&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Given:&amp;nbsp;&lt;/span&gt;18 + 6&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;times;&lt;/span&gt;&amp;nbsp;3 - 9&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;divide;&lt;/span&gt;&amp;nbsp;3 = ?&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;18 + 6&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;times;&lt;/span&gt;&amp;nbsp;3 - 9&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;divide;&lt;/span&gt;&amp;nbsp;3 = ?&amp;nbsp;&amp;rArr;&amp;nbsp;18 &lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;times;&lt;/span&gt; 6&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;+&lt;/span&gt;&amp;nbsp;3 &lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;divide;&lt;/span&gt; 9&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;-&lt;/span&gt;&amp;nbsp;3 = ?&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;18&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;times;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;6&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;&lt;u&gt;&lt;strong&gt;3&amp;nbsp;&lt;/strong&gt;&lt;/u&gt;&lt;/span&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;divide;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;u&gt;&lt;strong&gt;&amp;nbsp;9&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;-&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;3 = ?&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr;&amp;nbsp;&lt;/span&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;18&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;&amp;times;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;u&gt;&lt;strong&gt;&amp;nbsp;6&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;0.33&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;-&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;3 = ?&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; &lt;u&gt;&lt;strong&gt;108&lt;/strong&gt;&lt;/u&gt;&lt;/span&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;+&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;u&gt;&lt;strong&gt;&amp;nbsp;0.33&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;-&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;3 = ?&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr;&amp;nbsp;&lt;/span&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;108.33&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); text-align: center;&quot;&gt;-&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;u&gt;&lt;strong&gt;&amp;nbsp;3&lt;/strong&gt;&lt;/u&gt; = ?&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; 105.33 = ?&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Hence,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;quot;Option 4&amp;quot;&lt;/span&gt;&amp;nbsp;is the correct answer.&lt;/p&gt;<br><br>&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://storage.googleapis.com/tb-img/production/22/04/BODMAS.png&quot; style=&quot;width: 290px; height: 159px;&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;संकेतों को डिकोड करना:&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color: rgb(33, 37, 41); height: 50px; width: 200px;&quot;&gt;
